<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Kanban Board</title>
  <style>
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
      background: #f0f2f5;
      padding: 20px;
    }
    #board {
      display: flex;
      gap: 20px;
      margin-bottom: 20px;
    }
    .column {
      flex: 1;
      background: #fff;
      border-radius: 8px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.1);
      padding: 15px;
    }
    .column-header {
      display: flex;
      align-items: center;
      margin-bottom: 15px;
      padding-bottom: 10px;
      border-bottom: 1px solid #eee;
    }
    .column-title {
      font-weight: 600;
      font-size: 1.1em;
      flex: 1;
    }
    .count {
      background: #1a73e8;
      color: white;
      border-radius: 10px;
      padding: 4px 12px;
      font-size: 0.85em;
      font-weight: 500;
    }
    .cards-container {
      min-height: 200px;
      padding: 5px 0;
    }
    .card {
      background: #f8f9fa;
      border-radius: 6px;
      padding: 12px 15px;
      margin-bottom: 10px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      cursor: move;
      border-left: 3px solid transparent;
      transition: all 0.2s;
    }
    .card:hover {
      background: #fff;
      box-shadow: 0 2px 6px rgba(0,0,0,0.08);
    }
    .card.dragging {
      opacity: 0.5;
      transform: rotate(5deg);
    }
    .card-title {
      flex: 1;
      font-size: 0.95em;
      color: #333;
    }
    .card-del {
      background: none;
      border: none;
      color: #ea4335;
      font-size: 1.2em;
      cursor: pointer;
      padding: 0;
      line-height: 1;
      opacity: 0.7;
      transition: opacity 0.2s;
    }
    .card-del:hover {
      opacity: 1;
    }
    .controls {
      display: flex;
      gap: 10px;
      margin-bottom: 20px;
    }
    #new-card {
      flex: 1;
      padding: 12px 15px;
      border: 1px solid #ddd;
      border-radius: 6px;
      font-size: 1em;
      outline: none;
      transition: border-color 0.2s;
    }
    #new-card:focus {
      border-color: #1a73e8;
    }
    #add-card {
      padding: 12px 24px;
      background: #1a73e8;
      color: white;
      border: none;
      border-radius: 6px;
      font-size: 1em;
      cursor: pointer;
      transition: background 0.2s;
    }
    #add-card:hover {
      background: #1557b0;
    }
  </style>
</head>
<body>
  <div class="controls">
    <input id="new-card" type="text" placeholder="Enter new task...">
    <button id="add-card">Add Card</button>
  </div>

  <div id="board">
    <div id="col-todo" class="column">
      <div class="column-header">
        <span class="column-title">To Do</span>
        <span class="count">0</span>
      </div>
      <div class="cards-container"></div>
    </div>

    <div id="col-doing" class="column">
      <div class="column-header">
        <span class="column-title">Doing</span>
        <span class="count">0</span>
      </div>
      <div class="cards-container"></div>
    </div>

    <div id="col-done" class="column">
      <div class="column-header">
        <span class="column-title">Done</span>
        <span class="count">0</span>
      </div>
      <div class="cards-container"></div>
    </div>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      const columns = ['todo', 'doing', 'done'];

      function createCard(title) {
        const card = document.createElement('div');
        card.className = 'card';
        card.draggable = true;
        card.id = 'card-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

        const titleSpan = document.createElement('span');
        titleSpan.className = 'card-title';
        titleSpan.textContent = title;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.innerHTML = '&times;';

        card.appendChild(titleSpan);
        card.appendChild(delBtn);

        // Drag handlers
        card.addEventListener('dragstart', (e) => {
          e.dataTransfer.setData('text/plain', e.target.id);
          e.dataTransfer.effectAllowed = 'move';
          card.classList.add('dragging');
        });

        card.addEventListener('dragend', () => {
          card.classList.remove('dragging');
        });

        // Delete handler
        delBtn.addEventListener('click', () => {
          card.remove();
          updateCounts();
          saveState();
        });

        return card;
      }

      function updateCounts() {
        columns.forEach(col => {
          const container = document.querySelector(`#col-${col} .cards-container`);
          const count = container.querySelectorAll('.card').length;
          const countEl = document.querySelector(`#col-${col} .count`);
          countEl.textContent = count;
        });
      }

      function saveState() {
        const state = [];
        columns.forEach(col => {
          const container = document.querySelector(`#col-${col} .cards-container`);
          container.querySelectorAll('.card').forEach(card => {
            state.push({
              title: card.querySelector('.card-title').textContent,
              column: col
            });
          });
        });
        localStorage.setItem('kanbanState', JSON.stringify(state));
      }

      function loadState() {
        const saved = localStorage.getItem('kanbanState');
        if (saved) {
          try {
            const state = JSON.parse(saved);
            state.forEach(item => {
              const card = createCard(item.title);
              const container = document.querySelector(`#col-${item.column} .cards-container`);
              container.appendChild(card);
            });
            updateCounts();
          } catch (e) {
            console.error('Failed to load state:', e);
          }
        }
      }

      // Add card handler
      document.getElementById('add-card').addEventListener('click', () => {
        const input = document.getElementById('new-card');
        const title = input.value.trim();
        if (title) {
          const card = createCard(title);
          document.querySelector('#col-todo .cards-container').appendChild(card);
          input.value = '';
          updateCounts();
          saveState();
        }
      });

      // Input enter key handler
      document.getElementById('new-card').addEventListener('keypress', (e) => {
        if (e.key === 'Enter') {
          document.getElementById('add-card').click();
        }
      });

      // Column drop handlers
      columns.forEach(col => {
        const container = document.querySelector(`#col-${col} .cards-container`);

        container.addEventListener('dragover', (e) => {
          e.preventDefault();
          e.dataTransfer.dropEffect = 'move';
        });

        container.addEventListener('drop', (e) => {
          e.preventDefault();
          const cardId = e.dataTransfer.getData('text/plain');
          const card = document.getElementById(cardId);
          if (card && card.parentNode !== container) {
            container.appendChild(card);
            updateCounts();
            saveState();
          }
        });
      });

      // Initialize
      loadState();
    });
  </script>
</body>
</html>
